  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Disable X-Powered-By (defense in depth — helmet does this too)
app.disable('x-powered-by');

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const { id } = req.query;
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  if (id !== undefined) {
    const numericId = Number(id);
    if (!Number.isInteger(numericId) || numericId <= 0) {
      return res.status(400).json({ error: 'Invalid id parameter. Must be a positive integer.' });
    }
    const user = users.find((u) => u.id === numericId);
    if (!user) {
      return res.status(404).json({ error: 'User not found.' });
    }
    return res.json(user);
  }

  res.json(users);
});

// --- 404 Handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// --- Global Error Handler (must have 4 params) ---
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);
  // Never leak stack traces or internal details to the client
  res.status(500).json({ error: 'Internal server error.' });
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
